import React, { useContext, useState } from 'react';
import { Search, Scroll, Shield, ChevronLeft, MapPin, Coins, AlertTriangle, X } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/authContext';

const ScrollSearch = () => {
    // use context of logging in 
    const { currentUser } = useContext(AuthContext);
    const { id, username, link} = currentUser;

    // if currenUser exist then isLoggedIn is true
    //const [isLoggedIn, setIsLoggedIn] = useState((!!currentUser));
    const navigate = useNavigate();
    const handleBackClick = e =>{
        navigate("/");
    }

  const [searchTerm, setSearchTerm] = useState("");

  const allScrolls = [
    { id: 1, title: "Griffin Menace at White Orchard", location: "Temeria", reward: "500 Gold", difficulty: "Medium", type: "Monster Contract" },
    { id: 2, title: "Collect 500 Rupees for Shield Repair", location: "Hyrule", reward: "Hylian Shield", difficulty: "Easy", type: "Fetch Quest" },
    { id: 3, title: "Mako Reactor Maintenance", location: "Midgar", reward: "2000 Gil", difficulty: "Hard", type: "Industrial" },
    { id: 4, title: "Train Robbery Assistance", location: "New Hanover", reward: "150 Gold", difficulty: "Medium", type: "Outlaw" },
    { id: 5, title: "Goblin Den Clearing", location: "Borderlands", reward: "Small Pouch", difficulty: "Easy", type: "Monster Contract" },
    { id: 6, title: "The Ghost of the Lighthouse", location: "Skellige", reward: "1200 Gold", difficulty: "Hard", type: "Investigation" },
    { id: 7, title: "Lost Cucco Retrieval", location: "Kakariko Village", reward: "Purple Rupee", difficulty: "Easy", type: "Fetch Quest" },
  ];

  const filteredScrolls = allScrolls.filter(scroll =>
    scroll.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    scroll.location.toLowerCase().includes(searchTerm.toLowerCase()) ||
    scroll.type.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-[#3d2b1f]/60 font-serif text-[#4a3728] backdrop-blur-[2px] p-6 lg:p-10">
      
      {/* NAVIGATION */}
      <button className="mb-8 flex items-center gap-2 text-[#d7ccc8] hover:text-white transition-colors uppercase text-sm font-bold tracking-widest group"
        onClick={handleBackClick}
        >
        <ChevronLeft size={20} className="group-hover:-translate-x-1 transition-transform" />
        Return to Board
      </button>

      <div className="max-w-4xl mx-auto space-y-12">
        
        {/* REDESIGNED SEARCH SECTION: THE "LEDGER SCROLL" */}
        <section className="relative">
          <div className="text-center mb-8">
            <h1 className="text-5xl font-black text-[#f5f5dc] uppercase tracking-tighter drop-shadow-lg">
              Guild Archives
            </h1>
            <p className="text-[#d7ccc8] text-xs uppercase tracking-[0.4em] mt-2 opacity-60">Consult the ancient records</p>
          </div>

          <div className="relative max-w-2xl mx-auto">
            {/* Left Scroll Roller */}
            <div className="absolute -left-4 top-0 bottom-0 w-8 bg-[#3e2723] rounded-full shadow-2xl z-10 border-l-2 border-[#5d4037]" />
            
            {/* The Scroll Body */}
            <div 
              className="relative mx-2 bg-[#fdf6e3] border-y-4 border-[#3e2723] shadow-[0_10px_30px_rgba(0,0,0,0.5)] flex items-center px-8 py-4"
              style={{ backgroundImage: 'url("https://www.transparenttextures.com/patterns/paper-fibers.png")' }}
            >
              <div className="flex-1 flex items-center gap-4 border-b-2 border-[#8d6e63]/30">
                <Search className="text-[#8d6e63]" size={24} />
                <input 
                  type="text"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Inscribe your inquiry..."
                  className="w-full bg-transparent py-4 text-2xl focus:outline-none italic text-[#3e2723] placeholder-[#8d6e63]/40 font-medium"
                />
              </div>

              {/* Wax Seal Clear Button */}
              {searchTerm && (
                <button 
                  onClick={() => setSearchTerm("")}
                  className="ml-4 p-2 bg-[#8b0000] rounded-full text-[#f5f5dc] shadow-lg hover:scale-110 transition-transform active:scale-95"
                >
                  <X size={18} />
                </button>
              )}
            </div>

            {/* Right Scroll Roller */}
            <div className="absolute -right-4 top-0 bottom-0 w-8 bg-[#3e2723] rounded-full shadow-2xl z-10 border-r-2 border-[#5d4037]" />
          </div>
        </section>

        {/* RESULTS: PARCHMENT LEDGER */}
        <main 
          className="relative shadow-2xl border-2 border-[#3e2723]/20"
          style={{ 
            backgroundImage: 'url("https://www.transparenttextures.com/patterns/paper-fibers.png")',
            backgroundColor: 'rgba(253, 246, 227, 0.92)',
            backdropFilter: 'blur(10px)'
          }}
        >
          {/* Header of the Result Table */}
          <div className="bg-[#3e2723] text-[#d7ccc8] px-8 py-3 flex justify-between items-center text-[10px] font-black uppercase tracking-[0.2em]">
            <span>Record Entry</span>
            <span>Reward & Threat Level</span>
          </div>

          <div className="p-2">
            {filteredScrolls.length > 0 ? (
              <div className="divide-y-2 divide-[#d7ccc8]/50">
                {filteredScrolls.map((scroll) => (
                  <div 
                    key={scroll.id}
                    className="group flex flex-col md:flex-row md:items-center justify-between p-6 hover:bg-[#5d4037]/5 transition-colors cursor-pointer"
                  >
                    <div className="flex items-start gap-4">
                      <Scroll size={20} className="mt-1 text-[#8d6e63] group-hover:rotate-12 transition-transform" />
                      <div>
                        <h3 className="text-xl font-black text-[#3e2723] uppercase tracking-tight leading-none group-hover:text-[#b8860b]">
                          {scroll.title}
                        </h3>
                        <div className="flex gap-4 mt-2 text-[10px] font-bold text-[#8d6e63] uppercase tracking-widest">
                          <span className="flex items-center gap-1"><MapPin size={10} /> {scroll.location}</span>
                          <span className="opacity-40">/</span>
                          <span>{scroll.type}</span>
                        </div>
                      </div>
                    </div>

                    <div className="mt-4 md:mt-0 flex items-center gap-8">
                      <div className="text-right">
                        <p className="font-black text-[#5d4037] flex items-center justify-end gap-1 text-lg">
                          {scroll.reward}
                        </p>
                      </div>
                      <div className={`w-24 text-center py-1 text-[10px] font-black border-2 uppercase
                        ${scroll.difficulty === 'Hard' ? 'border-[#8b0000] text-[#8b0000]' : 
                          scroll.difficulty === 'Medium' ? 'border-[#5d4037] text-[#5d4037]' : 'border-[#2e4d2e] text-[#2e4d2e]'}`}>
                        {scroll.difficulty}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="py-20 text-center space-y-4">
                <AlertTriangle size={48} className="mx-auto text-[#8b0000] opacity-30" />
                <p className="text-xl font-black text-[#8d6e63] uppercase italic">No records found in the archive.</p>
              </div>
            )}
          </div>

          {/* Table Footer */}
          <div className="h-4 bg-[#3e2723] w-full" />
        </main>
      </div>

      <style dangerouslySetInnerHTML={{ __html: `
        body {
          background-image: url('https://i.pinimg.com/736x/c3/c2/65/c3c265c3f23e9f66fa132616a2c02370.jpg');
          background-size: cover;
          background-attachment: fixed;
        }
        input::placeholder {
          font-style: italic;
          opacity: 0.3;
          color: #3e2723;
        }
      `}} />
    </div>
  );
};

export default ScrollSearch;
